class PaymentCard {
  final String cardNumber;
  final String cardHolderName;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String? billingZip;

  PaymentCard({
    required this.cardNumber,
    required this.cardHolderName,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    this.billingZip,
  });

  bool validate() {
    if (!_validateCardNumber(cardNumber)) return false;
    if (!_validateExpiry(expiryMonth, expiryYear)) return false;
    if (!_validateCVV(cvv)) return false;
    return true;
  }

  bool _validateCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    
    int sum = 0;
    bool alternate = false;
    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool _validateExpiry(String month, String year) {
    final now = DateTime.now();
    final expMonth = int.tryParse(month);
    final expYear = int.tryParse(year);
    
    if (expMonth == null || expYear == null) return false;
    if (expMonth < 1 || expMonth > 12) return false;
    
    final fullYear = expYear < 100 ? 2000 + expYear : expYear;
    final expiryDate = DateTime(fullYear, expMonth + 1, 0);
    
    return expiryDate.isAfter(now);
  }

  bool _validateCVV(String cvv) {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }

  String get maskedNumber {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }

  Map<String, dynamic> toTokenizedMap() {
    return {
      'last4': cardNumber.replaceAll(RegExp(r'\s+'), '').substring(cardNumber.length - 4),
      'expMonth': expiryMonth,
      'expYear': expiryYear,
      'cardHolder': cardHolderName,
    };
  }
}

class Transaction {
  final String id;
  final double amount;
  final String currency;
  final PaymentMethod method;
  final TransactionStatus status;
  final DateTime timestamp;
  final Map<String, dynamic>? metadata;
  final String? errorMessage;

  Transaction({
    required this.id,
    required this.amount,
    required this.currency,
    required this.method,
    required this.status,
    required this.timestamp,
    this.metadata,
    this.errorMessage,
  });

  factory Transaction.fromJson(Map<String, dynamic> json) {
    return Transaction(
      id: json['id'],
      amount: json['amount'].toDouble(),
      currency: json['currency'],
      method: PaymentMethod.values.firstWhere(
        (e) => e.toString() == 'PaymentMethod.${json['method']}',
        orElse: () => PaymentMethod.creditCard,
      ),
      status: TransactionStatus.values.firstWhere(
        (e) => e.toString() == 'TransactionStatus.${json['status']}',
        orElse: () => TransactionStatus.pending,
      ),
      timestamp: DateTime.parse(json['timestamp']),
      metadata: json['metadata'],
      errorMessage: json['errorMessage'],
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'amount': amount,
      'currency': currency,
      'method': method.toString().split('.').last,
      'status': status.toString().split('.').last,
      'timestamp': timestamp.toIso8601String(),
      'metadata': metadata,
      'errorMessage': errorMessage,
    };
  }
}

