  Future<Transaction> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    Map<String, dynamic>? paymentDetails,
    Map<String, dynamic>? metadata,
  });

  Future<Transaction> refundTransaction(String transactionId, {double? amount});
  Future<Transaction> getTransactionStatus(String transactionId);
  Future<String> createPaymentToken(PaymentCard card);
}

class StripeGateway implements PaymentGateway {
  final String apiKey;
  final String publishableKey;
  final bool isTestMode;
  static const String _baseUrl = 'https://api.stripe.com/v1';

  StripeGateway({
    required this.apiKey,
    required this.publishableKey,
    this.isTestMode = false,
  });

  @override
  Future<String> createPaymentToken(PaymentCard card) async {
    if (!card.validate()) {
      throw PaymentSecurityException('Invalid card details');
    }

    final response = await http.post(
      Uri.parse('$_baseUrl/tokens'),
      headers: {
        'Authorization': 'Bearer $publishableKey',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {
        'card[number]': card.cardNumber.replaceAll(RegExp(r'\s+'), ''),
        'card[exp_month]': card.expiryMonth,
        'card[exp_year]': card.expiryYear,
        'card[cvc]': card.cvv,
        'card[name]': card.cardHolderName,
      },
    );

    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      return data['id'];
    } else {
      throw PaymentSecurityException('Failed to tokenize card');
    }
  }

  @override
  Future<Transaction> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    Map<String, dynamic>? paymentDetails,
    Map<String, dynamic>? metadata,
  }) async {
    final amountInCents = (amount * 100).toInt();
    
    final response = await http.post(
      Uri.parse('$_baseUrl/payment_intents'),
      headers: {
        'Authorization': 'Bearer $apiKey',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {
        'amount': amountInCents.toString(),
        'currency': currency.toLowerCase(),
        'payment_method': paymentDetails?['token'] ?? '',
        'confirm': 'true',
        'metadata': json.encode(metadata ?? {}),
      },
    );

    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      return Transaction(
        id: data['id'],
        amount: amount,
        currency: currency,
        method: method,
        status: _mapStripeStatus(data['status']),
        timestamp: DateTime.now(),
        metadata: metadata,
      );
    } else {
      final error = json.decode(response.body);
      throw PaymentSecurityException(error['error']['message']);
    }
  }

  @override
  Future<Transaction> refundTransaction(String transactionId, {double? amount}) async {
    final body = <String, String>{'payment_intent': transactionId};
    if (amount != null) {
      body['amount'] = (amount * 100).toInt().toString();
    }

    final response = await http.post(
      Uri.parse('$_baseUrl/refunds'),
      headers: {
        'Authorization': 'Bearer $apiKey',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body,
    );

    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      return Transaction(
        id: data['id'],
        amount: amount ?? 0,
        currency: data['currency'],
        method: PaymentMethod.stripe,
        status: TransactionStatus.refunded,
        timestamp: DateTime.now(),
      );
    } else {
      throw PaymentSecurityException('Refund failed');
    }
  }

  @override
  Future<Transaction> getTransactionStatus(String transactionId) async {
    final response = await http.get(
      Uri.parse('$_baseUrl/payment_intents/$transactionId'),
      headers: {'Authorization': 'Bearer $apiKey'},
    );

    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      return Transaction(
        id: data['id'],
        amount: data['amount'] / 100.0,
        currency: data['currency'],
        method: PaymentMethod.stripe,
        status: _mapStripeStatus(data['status']),
        timestamp: DateTime.fromMillisecondsSinceEpoch(data['created'] * 1000),
      );
    } else {
      throw PaymentSecurityException('Failed to get transaction status');
    }
  }

  TransactionStatus _mapStripeStatus(String status) {
    switch (status) {
      case 'succeeded':
        return TransactionStatus.completed;
      case 'processing':
        return TransactionStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
        return TransactionStatus.pending;
      case 'canceled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }
}

