class InAppPurchaseManager {
  static const MethodChannel _channel = MethodChannel('com.payment.iap');
  final StreamController<Transaction> _purchaseController = StreamController.broadcast();

  Stream<Transaction> get purchaseStream => _purchaseController.stream;

  Future<void> initialize() async {
    _channel.setMethodCallHandler(_handleMethodCall);
    await _channel.invokeMethod('initialize');
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    switch (call.method) {
      case 'onPurchaseUpdate':
        final transaction = Transaction.fromJson(call.arguments);
        _purchaseController.add(transaction);
        break;
    }
  }

  Future<List<Product>> getProducts(List<String> productIds) async {
    final result = await _channel.invokeMethod('getProducts', {'productIds': productIds});
    return (result as List).map((p) => Product.fromJson(p)).toList();
  }

  Future<Transaction> purchaseProduct(String productId) async {
    final result = await _channel.invokeMethod('purchaseProduct', {'productId': productId});
    return Transaction.fromJson(result);
  }

  Future<void> restorePurchases() async {
    await _channel.invokeMethod('restorePurchases');
  }

  Future<void> finishTransaction(String transactionId) async {
    await _channel.invokeMethod('finishTransaction', {'transactionId': transactionId});
  }

  void dispose() {
    _purchaseController.close();
  }
}

