class PaymentProcessor {
  final Map<PaymentMethod, PaymentGateway> _gateways = {};
  final InAppPurchaseManager _iapManager = InAppPurchaseManager();
  final StreamController<Transaction> _transactionController = StreamController.broadcast();

  Stream<Transaction> get transactionStream => _transactionController.stream;

  Future<void> initialize({
    String? stripeApiKey,
    String? stripePublishableKey,
  }) async {
    final isSecure = await DeviceSecurityValidator.isDeviceSecure();
    if (!isSecure) {
      throw PaymentSecurityException('Device security check failed');
    }

    if (stripeApiKey != null && stripePublishableKey != null) {
      _gateways[PaymentMethod.stripe] = StripeGateway(
        apiKey: stripeApiKey,
        publishableKey: stripePublishableKey,
      );
      _gateways[PaymentMethod.creditCard] = _gateways[PaymentMethod.stripe]!;
      _gateways[PaymentMethod.debitCard] = _gateways[PaymentMethod.stripe]!;
    }

    if (Platform.isIOS) {
      _gateways[PaymentMethod.applePay] = ApplePayGateway();
    }

    if (Platform.isAndroid) {
      _gateways[PaymentMethod.googlePay] = GooglePayGateway();
    }

    await _iapManager.initialize();
    _iapManager.purchaseStream.listen((transaction) {
      _transactionController.add(transaction);
    });
  }

  Future<Transaction> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    PaymentCard? card,
    Map<String, dynamic>? paymentDetails,
    Map<String, dynamic>? metadata,
    bool requireBiometric = true,
  }) async {
    final isSecure = await DeviceSecurityValidator.isDeviceSecure();
    if (!isSecure) {
      throw PaymentSecurityException('Device security check failed');
    }

    if (requireBiometric) {
      final authenticated = await DeviceSecurityValidator.authenticateUser();
      if (!authenticated) {
        throw PaymentSecurityException('Biometric authentication failed');
      }
    }

    final gateway = _gateways[method];
    if (gateway == null) {
      throw PaymentSecurityException('Payment method not supported');
    }

    try {
      Map<String, dynamic>? details = paymentDetails;
      
      if (card != null && (method == PaymentMethod.creditCard || method == PaymentMethod.debitCard)) {
        final token = await gateway.createPaymentToken(card);
        details = {'token': token, ...?paymentDetails};
      }

      final transaction = await gateway.processPayment(
        amount: amount,
        currency: currency,
        method: method,
        paymentDetails: details,
        metadata: metadata,
      );

      _transactionController.add(transaction);
      await _saveTransaction(transaction);
      
      return transaction;
    } catch (e) {
      final failedTransaction = Transaction(
        id: _generateTransactionId(),
        amount: amount,
        currency: currency,
        method: method,
        status: TransactionStatus.failed,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
        metadata: metadata,
      );
      
      _transactionController.add(failedTransaction);
      await _saveTransaction(failedTransaction);
      
      rethrow;
    }
  }

  Future<Transaction> refundPayment(String transactionId, {double? amount}) async {
    final transaction = await getTransaction(transactionId);
    if (transaction == null) {
      throw PaymentSecurityException('Transaction not found');
    }

    final gateway = _gateways[transaction.method];
    if (gateway == null) {
      throw PaymentSecurityException('Gateway not available');
    }

    final refundTransaction = await gateway.refundTransaction(transactionId, amount: amount);
    _transactionController.add(refundTransaction);
    await _saveTransaction(refundTransaction);
    
    return refundTransaction;
  }

  Future<List<Product>> getInAppProducts(List<String> productIds) async {
    return await _iapManager.getProducts(productIds);
  }

  Future<Transaction> purchaseInAppProduct(String productId) async {
    final isSecure = await DeviceSecurityValidator.isDeviceSecure();
    if (!isSecure) {
      throw PaymentSecurityException('Device security check failed');
    }

    return await _iapManager.purchaseProduct(productId);
  }

  Future<void> restoreInAppPurchases() async {
    await _iapManager.restorePurchases();
  }

  Future<void> _saveTransaction(Transaction transaction) async {
    final prefs = await SharedPreferences.getInstance();
    final transactions = prefs.getStringList('transactions') ?? [];
    transactions.add(json.encode(transaction.toJson()));
    await prefs.setStringList('transactions', transactions);
  }

  Future<Transaction?> getTransaction(String transactionId) async {
    final prefs = await SharedPreferences.getInstance();
    final transactions = prefs.getStringList('transactions') ?? [];
    
    for (final txnString in transactions) {
      final txn = Transaction.fromJson(json.decode(txnString));
      if (txn.id == transactionId) {
        return txn;
      }
    }
    
    return null;
  }

  Future<List<Transaction>> getAllTransactions() async {
    final prefs = await SharedPreferences.getInstance();
    final transactions = prefs.getStringList('transactions') ?? [];
    
    return transactions.map((txnString) {
      return Transaction.fromJson(json.decode(txnString));
    }).toList();
  }

  String _generateTransactionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = DateTime.now().microsecondsSinceEpoch;
    return 'txn_${timestamp}_$random';
  }

  void dispose() {
    _transactionController.close();
    _iapManager.dispose();
  }
}

class PaymentWidget extends StatefulWidget {
  final double amount;
  final String currency;
  final Function(Transaction) onSuccess;
  final Function(String) onError;

  const PaymentWidget({
    Key? key,
    required this.amount,
    required this.currency,
    required this.onSuccess,
    required this.onError,
  }) : super(key: key);

  @override
  State<PaymentWidget> createState() => _PaymentWidgetState();
}

class _PaymentWidgetState extends State<PaymentWidget> {
  final PaymentProcessor _processor = PaymentProcessor();
  PaymentMethod _selectedMethod = PaymentMethod.creditCard;
  bool _isProcessing = false;
  bool _canUseApplePay = false;
  bool _canUseGooglePay = false;

  final _cardNumberController = TextEditingController();
  final _cardHolderController = TextEditingController();
  final _expiryMonthController = TextEditingController();
  final _expiryYearController = TextEditingController();
  final _cvvController = TextEditingController();

  @override
  void initState() {
    super.initState();
    _initializePayment();
  }

  Future<void> _initializePayment() async {
    await _processor.initialize(
      stripeApiKey: 'your_stripe_secret_key',
      stripePublishableKey: 'your_stripe_publishable_key',
    );

    if (Platform.isIOS) {
      _canUseApplePay = await ApplePayGateway.canMakePayments();
    }

    if (Platform.isAndroid) {
      _canUseGooglePay = await GooglePayGateway.canMakePayments();
    }

    setState(() {});
  }

  Future<void> _processPayment() async {
    setState(() => _isProcessing = true);

    try {
      Transaction transaction;

      if (_selectedMethod == PaymentMethod.creditCard || _selectedMethod == PaymentMethod.debitCard) {
        final card = PaymentCard(
          cardNumber: _cardNumberController.text,
          cardHolderName: _cardHolderController.text,
          expiryMonth: _expiryMonthController.text,
          expiryYear: _expiryYearController.text,
          cvv: _cvvController.text,
        );

        transaction = await _processor.processPayment(
          amount: widget.amount,
          currency: widget.currency,
          method: _selectedMethod,
          card: card,
        );
      } else {
        transaction = await _processor.processPayment(
          amount: widget.amount,
          currency: widget.currency,
          method: _selectedMethod,
        );
      }

      widget.onSuccess(transaction);
    } catch (e) {
      widget.onError(e.toString());
    } finally {
      setState(() => _isProcessing = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Container();
  }

  @override
  void dispose() {
    _cardNumberController.dispose();
    _cardHolderController.dispose();
    _expiryMonthController.dispose();
    _expiryYearController.dispose();
    _cvvController.dispose();
    _processor.dispose();
    super.dispose();
  }
}